Dunder (double underscore) methods define how objects respond to built-in operations.

class Vector:
    def __init__(self, x, y):
        self.x, self.y = x, y
    def __repr__(self):
        return f'Vector({self.x}, {self.y})'
    def __add__(self, other):
        return Vector(self.x + other.x, self.y + other.y)
    def __len__(self):
        return 2
    def __getitem__(self, i):
        return [self.x, self.y][i]

v = Vector(1, 2)
print(v)     # calls __repr__
v + Vector(3, 4)  # calls __add__

