# Extended version for code files
def check_brackets(text, ignore_strings=True):
    stack = []
    pairs = {')': '(', '}': '{', ']': '['}
    in_string = False
    for i, c in enumerate(text):
        if ignore_strings and c in '"\'':
            in_string = not in_string
        if not in_string:
            if c in '({[': stack.append((c, i))
            elif c in ')}]':
                if not stack or stack[-1][0] != pairs[c]:
                    return False, i
                stack.pop()
    if stack:
        return False, stack[-1][1]
    return True, -1

