Closure for memoization:
function memoize(fn) {
  const cache = {};  // captured by closure
  return function(...args) {
    const key = JSON.stringify(args);
    if (key in cache) return cache[key];
    cache[key] = fn.apply(this, args);
    return cache[key];
  };
}

