# Using collections.deque for better performance:
from collections import deque

def is_balanced(s):
    stack = deque()
    close_to_open = {')': '(', '}': '{', ']': '['}
    for ch in s:
        if ch in '({[':
            stack.append(ch)
        elif ch in ')}]':
            if not stack or stack[-1] != close_to_open[ch]:
                return False
            stack.pop()
    return not stack

