// With cancel and flush
function debounce(fn, delay) {
  let timer;
  function debounced(...args) {
    clearTimeout(timer);
    timer = setTimeout(() => fn.apply(this, args), delay);
  }
  debounced.cancel = () => clearTimeout(timer);
  debounced.flush = () => { clearTimeout(timer); fn(); };
  return debounced;
}

