def is_balanced(s):
    opens = set('({[')
    closes = set(')}]')
    pairs = dict(zip(')}]', '({['))
    stack = []
    for c in s:
        if c in opens:
            stack.append(c)
        elif c in closes:
            if not stack or stack.pop() != pairs[c]:
                return False
    return not stack  # empty stack = balanced

