from contextlib import contextmanager

@contextmanager
def savepoint(db, name='sp'):
    db.execute(f'SAVEPOINT {name}')
    try:
        yield
        db.execute(f'RELEASE SAVEPOINT {name}')
    except Exception:
        db.execute(f'ROLLBACK TO SAVEPOINT {name}')
        raise

